(() => {
  "use strict";

  const rawHtml = atob('');

  if (typeof DOMParser === "undefined") {
    document.documentElement.textContent = rawHtml;
    return;
  }

  const parser = new DOMParser();
  const parsed = parser.parseFromString(rawHtml, "text/html");

  // Buang node berbahaya agar tidak ada script/objek eksternal yang dijalankan.
  const blockedSelectors = [
    "script",
    "iframe",
    "object",
    "embed",
    "base",
    "meta[http-equiv='refresh']",
    "link"
  ];
  parsed.querySelectorAll(blockedSelectors.join(",")).forEach((node) => node.remove());

  const urlAttrs = new Set(["src", "href", "xlink:href", "action", "formaction", "poster", "data"]);
  const isUnsafeUrl = (value) => {
    const v = String(value || "").trim().toLowerCase();
    if (!v) return false;
    if (v.startsWith("#")) return false;
    if (v.startsWith("/") || v.startsWith("./") || v.startsWith("../")) return false;
    if (v.startsWith("data:image/")) return false;
    if (v.startsWith("mailto:") || v.startsWith("tel:")) return false;
    return /^([a-z][a-z0-9+.-]*:|\/\/)/.test(v);
  };

  parsed.querySelectorAll("*").forEach((el) => {
    for (const attr of Array.from(el.attributes)) {
      const name = attr.name.toLowerCase();
      const value = attr.value;

      if (name.startsWith("on")) {
        el.removeAttribute(attr.name);
        continue;
      }

      if (name === "srcset") {
        if (/(^|,)\s*(https?:|\/\/|javascript:|data:(?!image\/))/i.test(value)) {
          el.removeAttribute(attr.name);
        }
        continue;
      }

      if (urlAttrs.has(name) && isUnsafeUrl(value)) {
        el.removeAttribute(attr.name);
        continue;
      }

      if (name === "style" && /url\s*\(\s*['"]?\s*(https?:|\/\/)/i.test(value)) {
        el.removeAttribute(attr.name);
      }
    }
  });

  const csp = parsed.createElement("meta");
  csp.setAttribute("http-equiv", "Content-Security-Policy");
  csp.setAttribute(
    "content",
    "default-src 'self' data: blob:; script-src 'none'; connect-src 'none'; frame-src 'none'; object-src 'none';"
  );
  if (parsed.head.firstChild) {
    parsed.head.insertBefore(csp, parsed.head.firstChild);
  } else {
    parsed.head.appendChild(csp);
  }

  document.head.innerHTML = parsed.head.innerHTML;
  document.body.innerHTML = parsed.body.innerHTML;
})();
